<body>
  <div class="header">
    <h1>⚡ NullByte CVE Triage Report</h1>
    <p>Generated: ${new Date().toISOString()} | Pipeline: Automated Weekly Scan</p>
  </div>

  <div class="summary">
    <div class="stat">
      <div class="number">${items.length}</div>
      <div class="label">CVEs Analyzed</div>
