    <div class="stat">
      <div class="number">${items.filter(i => (i.json.triage||'').toLowerCase().includes('high')).length}</div>
      <div class="label">High</div>
    </div>
    <div class="stat">
      <div class="number">${items.filter(i => i.json.osv_confirmed).length}</div>
      <div class="label">OSV Confirmed</div>
    </div>
