const binary = Buffer.from(html, 'utf8').toString('base64');

return [{
  json: { fileName: 'nullbyte_report.html' },
  binary: {
    report: {
      data: binary,
      mimeType: 'text/html',
      fileName: 'nullbyte_report.html'
    }
  }
}];

const items = $input.all();
const results = [];

for (const item of items) {
  const cveId = item.json.cveId;
  let osvData = null;

  try {
    const response = await fetch(`https://api.osv.dev/v1/vulns/${cveId}`);
    if (response.ok) {
      osvData = await response.json();
    }
  } catch (e) {
    // OSV not available or CVE not found — continue
  }

  results.push({
    json: {
      ...item.json,
      osv_confirmed: osvData !== null,
      osv_severity: osvData?.severity?.[0]?.score ?? null,
      osv_aliases: osvData?.aliases ?? [],
      osv_modified: osvData?.modified ?? null,
      osv_cross_referenced: true
    }
  });
}

return results;
